async (params, browser) => {
  // Open user feed
  await browser.open(`https://bsky.app/profile/${params.handle}`)

  // Wait for feed
  await browser.waitForSelector('[data-testid^=\'feedItem-by-\'], [data-testid=\'postText\']', 15000)

  await browser.wait(2000)

  // Scroll for more posts
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract feed posts
  const feed_data = await browser.evaluate(`const posts = []; const feedItems = document.querySelectorAll('[data-testid^="feedItem-by-"]'); for (let i = 0; i < Math.min(feedItems.length, 20); i++) { const el = feedItems[i]; const contentEl = el.querySelector('[data-testid="postText"]'); const likeBtn = el.querySelector('[data-testid="likeBtn"]'); const replyBtn = el.querySelector('[data-testid="replyBtn"]'); const timeEl = el.querySelector('time'); const linkEl = el.querySelector('a[href*="/post/"]'); const imgEl = el.querySelector('img[src*="feed_"], img[src*="cdn"]'); posts.push({ content: contentEl ? contentEl.textContent.trim().substring(0, 500) : '', likes: likeBtn ? (likeBtn.getAttribute('aria-label') || '') : '', replies: replyBtn ? (replyBtn.getAttribute('aria-label') || '') : '', time: timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : '', url: linkEl ? linkEl.href : '', has_image: !!imgEl }); } const nameEl = document.querySelector('[data-testid="profileHeaderDisplayName"]'); return { handle: '' + params.handle + '', display_name: nameEl ? nameEl.textContent.trim() : '', post_count: posts.length, posts: posts, url: window.location.href }`)

  return feed_data
}
